import psycopg2
import re
from typing import List, Set
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class PostgreSQLExtensionManager:
    ALLOWED_EXTENSIONS: Set[str] = {
        'plpgsql',
        'hstore',
        'uuid-ossp',
        'postgis',
        'pg_trgm',
        'btree_gist',
        'btree_gin',
        'citext',
        'cube',
        'dblink',
        'dict_int',
        'earthdistance',
        'fuzzystrmatch',
        'intarray',
        'isn',
        'lo',
        'ltree',
        'pg_stat_statements',
        'pgcrypto',
        'pgrowlocks',
        'pg_buffercache',
        'pg_freespacemap',
        'pg_visibility',
        'seg',
        'tablefunc',
        'tcn',
        'tsm_system_rows',
        'tsm_system_time',
        'unaccent',
        'xml2',
        'plpythonu',
        'plpython3u',
        'plperl',
        'plperlu',
        'pltcl',
        'pltclu'
    }
    
    def __init__(self, host: str, database: str, user: str, password: str, port: int = 5432):
        self.connection_params = {
            'host': host,
            'database': database,
            'user': user,
            'password': password,
            'port': port
        }
        self.conn = None
        self.cursor = None
    
    def connect(self):
        try:
            self.conn = psycopg2.connect(**self.connection_params)
            self.conn.autocommit = False
            self.cursor = self.conn.cursor()
            logger.info("Successfully connected to PostgreSQL database")
        except psycopg2.Error as e:
            logger.error(f"Database connection error: {e}")
            raise
    
    def disconnect(self):
        if self.cursor:
            self.cursor.close()
        if self.conn:
            self.conn.close()
            logger.info("Database connection closed")
    
    def validate_extension_name(self, extension_name: str) -> bool:
        if not extension_name:
            logger.warning("Empty extension name provided")
            return False
        
        if not re.match(r'^[a-z0-9_-]+$', extension_name):
            logger.warning(f"Invalid extension name format: {extension_name}")
            return False
        
        if extension_name not in self.ALLOWED_EXTENSIONS:
            logger.warning(f"Extension not in allowed list: {extension_name}")
            return False
        
        return True
    
    def check_extension_exists(self, extension_name: str) -> bool:
        try:
            query = "SELECT EXISTS(SELECT 1 FROM pg_extension WHERE extname = %s)"
            self.cursor.execute(query, (extension_name,))
            result = self.cursor.fetchone()
            return result[0] if result else False
        except psycopg2.Error as e:
            logger.error(f"Error checking extension existence: {e}")
            return False
    
    def check_extension_available(self, extension_name: str) -> bool:
        try:
            query = "SELECT EXISTS(SELECT 1 FROM pg_available_extensions WHERE name = %s)"
            self.cursor.execute(query, (extension_name,))
            result = self.cursor.fetchone()
            return result[0] if result else False
        except psycopg2.Error as e:
            logger.error(f"Error checking extension availability: {e}")
            return False
    
    def install_extension(self, extension_name: str, if_not_exists: bool = True, cascade: bool = False) -> bool:
        if not self.validate_extension_name(extension_name):
            logger.error(f"Extension validation failed: {extension_name}")
            return False
        
        if self.check_extension_exists(extension_name):
            logger.info(f"Extension '{extension_name}' is already installed")
            return True
        
        if not self.check_extension_available(extension_name):
            logger.error(f"Extension '{extension_name}' is not available in this PostgreSQL installation")
            return False
        
        try:
            query_parts = ["CREATE EXTENSION"]
            
            if if_not_exists:
                query_parts.append("IF NOT EXISTS")
            
            query_parts.append(psycopg2.sql.Identifier(extension_name).as_string(self.cursor))
            
            if cascade:
                query_parts.append("CASCADE")
            
            query = " ".join(query_parts)
            
            logger.info(f"Executing: {query}")
            self.cursor.execute(query)
            self.conn.commit()
            
            logger.info(f"Successfully installed extension: {extension_name}")
            return True
            
        except psycopg2.Error as e:
            self.conn.rollback()
            logger.error(f"Error installing extension '{extension_name}': {e}")
            return False
    
    def install_extensions_batch(self, extension_names: List[str], cascade: bool = False) -> dict:
        results = {}
        
        for extension_name in extension_names:
            extension_name = extension_name.strip().lower()
            success = self.install_extension(extension_name, if_not_exists=True, cascade=cascade)
            results[extension_name] = success
        
        return results
    
    def list_installed_extensions(self) -> List[dict]:
        try:
            query = """
                SELECT extname, extversion, extrelocatable, nspname
                FROM pg_extension e
                JOIN pg_namespace n ON e.extnamespace = n.oid
                ORDER BY extname
            """
            self.cursor.execute(query)
            results = self.cursor.fetchall()
            
            extensions = []
            for row in results:
                extensions.append({
                    'name': row[0],
                    'version': row[1],
                    'relocatable': row[2],
                    'schema': row[3]
                })
            
            return extensions
        except psycopg2.Error as e:
            logger.error(f"Error listing installed extensions: {e}")
            return []
    
    def list_available_extensions(self) -> List[dict]:
        try:
            query = """
                SELECT name, default_version, installed_version, comment
                FROM pg_available_extensions
                ORDER BY name
            """
            self.cursor.execute(query)
            results = self.cursor.fetchall()
            
            extensions = []
            for row in results:
                extensions.append({
                    'name': row[0],
                    'default_version': row[1],
                    'installed_version': row[2],
                    'comment': row[3]
                })
            
            return extensions
        except psycopg2.Error as e:
            logger.error(f"Error listing available extensions: {e}")
            return []
    
    def uninstall_extension(self, extension_name: str, cascade: bool = False, if_exists: bool = True) -> bool:
        if not self.validate_extension_name(extension_name):
            logger.error(f"Extension validation failed: {extension_name}")
            return False
        
        try:
            query_parts = ["DROP EXTENSION"]
            
            if if_exists:
                query_parts.append("IF EXISTS")
            
            query_parts.append(psycopg2.sql.Identifier(extension_name).as_string(self.cursor))
            
            if cascade:
                query_parts.append("CASCADE")
            
            query = " ".join(query_parts)
            
            logger.info(f"Executing: {query}")
            self.cursor.execute(query)
            self.conn.commit()
            
            logger.info(f"Successfully uninstalled extension: {extension_name}")
            return True
            
        except psycopg2.Error as e:
            self.conn.rollback()
            logger.error(f"Error uninstalling extension '{extension_name}': {e}")
            return False


